DO $$ 
DECLARE 
  max_id bigint;
  is_ident varchar;
  dtype varchar;
BEGIN
  SELECT is_identity, data_type INTO is_ident, dtype
  FROM information_schema.columns 
  WHERE table_schema = 'public' 
    AND table_name = 'clients' 
    AND column_name = 'id';

  IF is_ident IS NOT NULL AND dtype IN ('integer', 'bigint', 'smallint') THEN
    EXECUTE 'SELECT MAX("id") FROM public."clients"' INTO max_id;
    IF max_id IS NOT NULL THEN
      IF is_ident = 'YES' THEN
        EXECUTE 'ALTER TABLE public."clients" ALTER COLUMN "id" RESTART WITH ' || (max_id + 1);
      ELSE
        EXECUTE 'SELECT setval(pg_get_serial_sequence(''public."clients"'', ''id''), ' || max_id || ')';
      END IF;
    END IF;
  END IF;
END $$;

